ee:variables.ee:set-variable:
%dw 2.0
output application/java

fun safeString(data: Any) = do {
    var raw = if (data == null) "" else if (typeOf(data) == String) data as String else if (typeOf(data) == Binary) data as String else if (data.^raw != null) data.^raw as String else ""
    ---
    raw replace /^\uFEFF/ with ""
}

fun parseToArrays(rawText: String) = do {
    var records = rawText splitBy /(?:\r\n|\n|\r)(?=[a-zA-Z0-9\-]{4,30}[ \t]*\|\|)/
    var firstRecordLines = records[0] splitBy /(?:\r\n|\n|\r)/
    var headerLine = (firstRecordLines filter ((line) -> line contains "||"))[-1] default ""
    var headers = headerLine splitBy "||" map trim($)
    var dataRows = records[1 to -1] default []
    ---
    {
        headers : headers,
        rows : dataRows map ((rowStr) -> rowStr splitBy "||" map (trim($) replace /\r\n?/ with "\n") )
    }
}

var parsed = parseToArrays(safeString(vars.rawFileContent))
var lHeaders = parsed.headers map lower($)
var foundScIdIdx = lHeaders indexOf "service_call_id"
var scIdIdx = if (foundScIdIdx >= 0) foundScIdIdx else 0
---
{
    headers : parsed.headers,
    map : parsed.rows groupBy $[scIdIdx]
}

%dw 2.0
output application/java

fun safeString(data: Any) = do {
    var raw = if (data == null) "" else if (typeOf(data) == String) data as String else if (typeOf(data) == Binary) data as String else if (data.^raw != null) data.^raw as String else ""
    ---
    raw replace /^\uFEFF/ with ""
}

fun parseToArrays(rawText: String) = do {
    var records = rawText splitBy /(?:\r\n|\n|\r)(?=[a-zA-Z0-9\-]{4,30}[ \t]*\|\|)/
    var firstRecordLines = records[0] splitBy /(?:\r\n|\n|\r)/
    var headerLine = (firstRecordLines filter ((line) -> line contains "||"))[-1] default ""
    var headers = headerLine splitBy "||" map trim($)
    var dataRows = records[1 to -1] default []
    ---
    {
        headers : headers,
        rows : dataRows map ((rowStr) -> rowStr splitBy "||" map (trim($) replace /\r\n?/ with "\n") )
    }
}

var parsed = parseToArrays(safeString(vars.rawFileContent))
var lHeaders = parsed.headers map lower($)
var foundScIdIdx = lHeaders indexOf "service_call_id"
var scIdIdx = if (foundScIdIdx >= 0) foundScIdIdx else 0
var itemdescIdx = lHeaders indexOf "itemdesc"
var itemnmbrIdx = lHeaders indexOf "itemnmbr"
var categoryIdx = lHeaders indexOf "itemcategory"
var trxqtyIdx = lHeaders indexOf "trxqty"
var billingIdx = lHeaders indexOf "billing_amount"
---
{
    joinMap: parsed.rows groupBy $[scIdIdx] mapObject ((groupRows, groupKey) -> {
        (groupKey as String): groupRows map (row) -> {
            ITEMDESC : trim((row[itemdescIdx] default '') replace /\u0000/ with ''),
            ITEMNMBR : trim((row[itemnmbrIdx] default '') replace /\u0000/ with ''),
            ItemCategory : trim((row[categoryIdx] default '') replace /\u0000/ with ''),
            TRXQTY : row[trxqtyIdx] default '0',
            Billing_Amount: row[billingIdx] default '0'
        }
    }),
    
    catalogEntries: (
        parsed.rows reduce ((row, acc = {}) -> do {
            var rawDesc = trim((row[itemdescIdx] default '') replace /\u0000/ with '')
            var matKey = lower(rawDesc)
            ---
            if (rawDesc == '' or acc[matKey]?) acc else acc ++ {
                (matKey): {
                    itemdesc : rawDesc,
                    itemnmbr : do {
                        var c = trim((row[itemnmbrIdx] default '') replace /\u0000/ with '')
                        ---
                        if (c == '') null else c
                    },
                    item_category : do {
                        var c = trim((row[categoryIdx] default '') replace /\u0000/ with '')
                        ---
                        if (c == '') null else c
                    },
                    materialKey : matKey
                }
            }
        })
    ) pluck (v) -> v
}

